SELECT

FROM
    dm_worker
WHERE
    worker_state = #{workerState,javaType=com.clougence.clouddm.api.console.status.WorkerState}
    AND cluster_id = #{clusterId}

mapper.update:
UPDATE
    dm_worker
SET
    worker_state = #{workerState,javaType=com.clougence.clouddm.api.console.status.WorkerState}
WHERE
    id = #{workerId}

UPDATE
    dm_worker
SET
    life_cycle_state = #{lifeCycleState,javaType=com.clougence.clouddm.console.web.dal.enumeration.LifeCycleState}
WHERE
    id = #{workerId}

UPDATE
    dm_worker
SET
    external_ip = #{externalIp}
WHERE
    id = #{workerId}

UPDATE
    dm_worker
SET
    worker_ip = #{workerIp}
WHERE
    id = #{workerId}

UPDATE
    dm_worker
SET
    worker_desc = #{workerDesc}
WHERE
    id = #{workerId}

UPDATE
    dm_worker
SET
    upgrade_all_console_job_id= #{upgradeAllConsoleJobId}
WHERE
